const PRINT_ATTR = 'data-lin-report-print';

/**
 * Scoped ERP report print — sets html attribute so @media print hides shell/sidebar.
 * Only `[data-report-list-page]` subtree is visible (title summary + grid).
 */
export function triggerErpReportPrint(onAfterPrint?: () => void): void {
  const root = document.documentElement;
  root.setAttribute(PRINT_ATTR, '');

  const cleanup = () => {
    root.removeAttribute(PRINT_ATTR);
    onAfterPrint?.();
  };

  window.addEventListener('afterprint', cleanup, { once: true });
  window.print();
}
