import React from 'react';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Legend,
  Line,
  LineChart,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { formatVnd } from '../../utils/formatters';
import type { LedgerChartData } from './buildLedgerChartData';
import { formatChartVndAxis } from './buildLedgerChartData';

export type LedgerChartViewLabels = {
  seriesDebit: string;
  seriesCredit: string;
  seriesBalanceDebit: string;
  seriesBalanceCredit: string;
};

export type LedgerChartViewProps = {
  kind: 'line' | 'bar' | 'donut';
  chartId: string;
  chartData: LedgerChartData;
  labels: LedgerChartViewLabels;
  height: number;
  testId: string;
};

export const LedgerChartView: React.FC<LedgerChartViewProps> = ({
  kind,
  chartId,
  chartData,
  labels,
  height,
  testId,
}) => {
  if (kind === 'line') {
    if (chartData.balanceSeries.length === 0) {
      return (
        <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }} data-testid={testId}>
          —
        </div>
      );
    }

    return (
      <ResponsiveContainer width="100%" height={height} data-testid={testId}>
        <LineChart data={chartData.balanceSeries} margin={{ top: 8, right: 12, left: 4, bottom: 4 }}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="label" tick={{ fontSize: 11 }} interval="preserveStartEnd" />
          <YAxis tickFormatter={formatChartVndAxis} width={52} tick={{ fontSize: 11 }} />
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
          <Line
            type="monotone"
            dataKey="balanceDebit"
            name={labels.seriesBalanceDebit}
            stroke="#1677ff"
            strokeWidth={2}
            dot={{ r: 3 }}
            activeDot={{ r: 5 }}
          />
          <Line
            type="monotone"
            dataKey="balanceCredit"
            name={labels.seriesBalanceCredit}
            stroke="#fa8c16"
            strokeWidth={2}
            dot={{ r: 3 }}
            activeDot={{ r: 5 }}
          />
        </LineChart>
      </ResponsiveContainer>
    );
  }

  if (kind === 'bar') {
    return (
      <ResponsiveContainer width="100%" height={height} data-testid={testId}>
        <BarChart data={chartData.dailySeries} margin={{ top: 8, right: 12, left: 4, bottom: 4 }}>
          <CartesianGrid strokeDasharray="3 3" />
          <XAxis dataKey="label" tick={{ fontSize: 11 }} />
          <YAxis tickFormatter={formatChartVndAxis} width={52} tick={{ fontSize: 11 }} />
          <Tooltip formatter={(v: number) => formatVnd(v)} />
          <Legend />
          <Bar dataKey="debit" name={labels.seriesDebit} fill="#1677ff" radius={[2, 2, 0, 0]} />
          <Bar dataKey="credit" name={labels.seriesCredit} fill="#fa8c16" radius={[2, 2, 0, 0]} />
        </BarChart>
      </ResponsiveContainer>
    );
  }

  if (chartData.donutSeries.length === 0) {
    return (
      <div style={{ height, display: 'flex', alignItems: 'center', justifyContent: 'center' }} data-testid={testId}>
        —
      </div>
    );
  }

  return (
    <ResponsiveContainer width="100%" height={height} data-testid={testId}>
      <PieChart>
        <Pie
          data={chartData.donutSeries}
          dataKey="value"
          nameKey="name"
          cx="50%"
          cy="50%"
          innerRadius="52%"
          outerRadius="78%"
          paddingAngle={2}
        >
          {chartData.donutSeries.map((entry, index) => (
            <Cell key={`${chartId}-cell-${index}`} fill={entry.fill} />
          ))}
        </Pie>
        <Tooltip formatter={(v: number) => formatVnd(v)} />
        <Legend />
      </PieChart>
    </ResponsiveContainer>
  );
};
