/** SSOT — aligned with `@linm-soft-org/linm-web-common-components` `erpListRowEditHintDismiss.ts`. */
export const ERP_LIST_ROW_EDIT_HINT_DISMISS_STORAGE_KEY = 'linm.erp.list-row-edit-hint.understood';

import { getGridItem, setGridItem } from '@linm-soft-org/linm-web-common-components';

export function isRowEditHintDismissed(storageKey: string): boolean {
  if (typeof window === 'undefined') return false;
  try {
    return getGridItem<string>(storageKey, (s: string) => s) === '1';
  } catch {
    return false;
  }
}

export function setRowEditHintDismissed(storageKey: string): void {
  if (typeof window === 'undefined') return;
  try {
    setGridItem(storageKey, '1');
  } catch {
    /* ignore quota / private mode */
  }
}
