import type { ViewMode } from '@linm-soft-org/linm-web-common-components';
import type { ReportPrintFilterLine } from '../components/report/ReportPrintSummary';
import { formatDateLocal } from './formatters';

export function formatReportDateRange(from?: string, to?: string): string {
  const fromStr = from ? formatDateLocal(from) : '';
  const toStr = to ? formatDateLocal(to) : '';
  if (fromStr && toStr) return `${fromStr} – ${toStr}`;
  if (fromStr) return `Từ ${fromStr}`;
  if (toStr) return `Đến ${toStr}`;
  return 'Tất cả';
}

export type SoCaiAppliedFilters = {
  accountCode: string;
  accountName?: string;
  fromDate?: string;
  toDate?: string;
};

export type SoChiTietAppliedFilters = {
  month: string;
  year: string;
  quarter: string;
  viewMode: ViewMode;
  accountCode: string;
  accountName?: string;
  fromDate?: string;
  toDate?: string;
};

export function buildSoChiTietPrintFilterLines(
  applied: SoChiTietAppliedFilters,
  labels: { fieldAccount: string; fieldPeriod?: string },
): ReportPrintFilterLine[] {
  const accountValue = applied.accountName
    ? `${applied.accountCode} — ${applied.accountName}`
    : applied.accountCode;

  const mode = applied.viewMode ?? 'month';
  let periodValue: string;

  if (mode === 'quarter') {
    periodValue = `Quý ${applied.quarter}/${applied.year}`;
  } else if (mode === 'month') {
    periodValue = `Tháng ${applied.month.padStart(2, '0')}/${applied.year}`;
  } else {
    periodValue = `${applied.fromDate ? formatDateLocal(applied.fromDate) : ''} – ${applied.toDate ? formatDateLocal(applied.toDate) : ''}`;
  }

  return [
    { label: labels.fieldAccount, value: accountValue },
    {
      label: labels.fieldPeriod ?? 'Kỳ',
      value: periodValue,
    },
  ];
}

export type MonthYearAppliedFilters = { month: string; year: string; viewMode?: ViewMode; quarter?: string };

export function buildMonthYearPrintFilterLines(
  applied: MonthYearAppliedFilters,
  labels: { fieldPeriod?: string },
): ReportPrintFilterLine[] {
  const mode = applied.viewMode ?? 'month';
  let periodValue: string;

  if (mode === 'quarter') {
    periodValue = `Quý ${applied.quarter}/${applied.year}`;
  } else if (mode === 'month') {
    periodValue = `Tháng ${applied.month.padStart(2, '0')}/${applied.year}`;
  } else {
    // day mode — use fromDate/toDate
    // applied filters in day mode may not have fromDate/toDate in the print filter shape
    periodValue = `Tháng ${applied.month.padStart(2, '0')}/${applied.year}`;
  }

  return [
    {
      label: labels.fieldPeriod ?? 'Kỳ',
      value: periodValue,
    },
  ];
}

export type CongNoAppliedFilters = {
  asOfDate: string;
  customerType?: string;
};

export function buildCongNoPrintFilterLines(
  applied: CongNoAppliedFilters,
  labels: { fieldAsOfDate: string; fieldCustomerType?: string; customerTypeAll?: string },
): ReportPrintFilterLine[] {
  const lines: ReportPrintFilterLine[] = [
    { label: labels.fieldAsOfDate, value: formatDateLocal(applied.asOfDate) },
  ];
  if (applied.customerType) {
    lines.push({ label: labels.fieldCustomerType ?? 'Loại đối tượng', value: applied.customerType });
  } else if (labels.customerTypeAll) {
    lines.push({ label: labels.fieldCustomerType ?? 'Loại đối tượng', value: labels.customerTypeAll });
  }
  return lines;
}

export function buildSoCaiPrintFilterLines(
  applied: SoCaiAppliedFilters,
  labels: { fieldAccount: string; fieldDateRange?: string },
): ReportPrintFilterLine[] {
  const accountValue = applied.accountName
    ? `${applied.accountCode} — ${applied.accountName}`
    : applied.accountCode;

  return [
    { label: labels.fieldAccount, value: accountValue },
    {
      label: labels.fieldDateRange ?? 'Thời gian',
      value: formatReportDateRange(applied.fromDate, applied.toDate),
    },
  ];
}

export type CashLedgerAppliedFilters = {
  accountCode?: string;
  accountName?: string;
  fromDate?: string;
  toDate?: string;
};

export function buildCashLedgerPrintFilterLines(
  applied: CashLedgerAppliedFilters,
  labels: { fieldAccount?: string; fieldDateRange?: string; accountAllLabel?: string },
): ReportPrintFilterLine[] {
  const lines: ReportPrintFilterLine[] = [];
  if (labels.fieldAccount) {
    const accountValue = applied.accountCode
      ? (applied.accountName ? `${applied.accountCode} — ${applied.accountName}` : applied.accountCode)
      : (labels.accountAllLabel ?? 'Tất cả TK tiền');
    lines.push({ label: labels.fieldAccount, value: accountValue });
  }
  lines.push({
    label: labels.fieldDateRange ?? 'Thời gian',
    value: formatReportDateRange(applied.fromDate, applied.toDate),
  });
  return lines;
}
