import { flushSync } from 'react-dom';
import { triggerErpReportPrint } from './triggerErpReportPrint';

const PRINT_LAYOUT_MS = 80;

/**
 * Apply print DOM state synchronously, wait for layout, then scoped print.
 */
export function runErpReportPrintAfterPaint(
  applyPrintState: () => void,
  onAfterPrint?: () => void,
): void {
  flushSync(applyPrintState);

  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      window.setTimeout(() => {
        triggerErpReportPrint(onAfterPrint);
      }, PRINT_LAYOUT_MS);
    });
  });
}
